import React, { useContext } from "react";
import { Link, graphql } from "gatsby";
import Layout, { LangContext } from "../components/Layout";
import SEO from "../components/SEO";
import ReportCard from "../components/ReportCard";
import SignalHeatmap from "../components/SignalHeatmap";
import DataPanel from "../components/DataPanel";
import { pickLangNodes, langSlug } from "../utils/i18n";

const CATEGORY_META = {
  "world-crypto": { label: "Global Crypto Intelligence", labelVi: "Tình báo Crypto Toàn cầu", icon: "🌐", color: "#8B5CF6" },
  "trend-scout": { label: "Trend Scout", labelVi: "Trinh sát Xu hướng", icon: "🔍", color: "#10B981" },
  "vn-legal-watch": { label: "Vietnam Legal Watch", labelVi: "Theo dõi Pháp lý VN", icon: "⚖️", color: "#F59E0B" },
  "product-engineer": { label: "Product Engineer", labelVi: "Kỹ sư Sản phẩm", icon: "🛠️", color: "#0066CC" },
  "crypto-catalyst": { label: "Crypto Catalyst Sentinel", labelVi: "Theo dõi Biến động Crypto", icon: "⚡", color: "#FF4500" },
  "dataset-marketplace": { label: "Dataset Marketplace", labelVi: "Thị trường Dataset", icon: "📊", color: "#6366F1" },
  "concept-monetizer": { label: "Concept Monetizer", labelVi: "Kiếm tiền từ Ý tưởng", icon: "💰", color: "#22C55E" },
};

function getCategoryMeta(category, lang) {
  const m = CATEGORY_META[category] || { label: category, labelVi: category, icon: "📄", color: "#888888" };
  return { ...m, displayLabel: lang === "vi" ? m.labelVi : m.label };
}

const IndexPage = ({ data }) => {
  const { lang } = useContext(LangContext);
  const allNodes = data.allMarkdownRemark.nodes;
  const reports = pickLangNodes(allNodes, lang);

  const dailyReports = reports.filter((r) => r.fields?.reportType !== "on-demand");
  const onDemandReports = reports.filter((r) => r.fields?.reportType === "on-demand");

  const categoryGroups = {};
  dailyReports.forEach((r) => {
    const cat = r.fields?.category || "uncategorized";
    if (!categoryGroups[cat]) categoryGroups[cat] = [];
    categoryGroups[cat].push(r);
  });

  const sortedCategories = Object.entries(categoryGroups).sort(([, a], [, b]) => {
    const dateA = a[0]?.fields?.date || "";
    const dateB = b[0]?.fields?.date || "";
    return dateB.localeCompare(dateA) || b.length - a.length;
  });

  const labels = {
    latestIntel: lang === "vi" ? "📡 Tình báo Mới nhất" : "📡 Latest Intelligence",
    dailyReports: lang === "vi" ? "📋 Báo cáo Hàng ngày" : "📋 Daily Reports",
    dailySub: lang === "vi" ? "Tình báo hàng ngày tự động từ 7 agent phân tích" : "Automated daily intelligence from 7 analyst agents",
    onDemand: lang === "vi" ? "🎯 Phân tích theo Yêu cầu" : "🎯 On-Demand Analysis",
    onDemandSub: lang === "vi" ? "Báo cáo nghiên cứu chuyên sâu tạo theo yêu cầu" : "Deep-dive research reports generated on request",
    categories: lang === "vi" ? "🗂 Danh mục Hàng ngày" : "🗂 Daily Categories",
    onDemandSide: lang === "vi" ? "🎯 Báo cáo theo Yêu cầu" : "🎯 On-Demand Reports",
    stats: lang === "vi" ? "📊 Thống kê" : "📊 Stats",
    total: lang === "vi" ? "Tổng Báo cáo" : "Total Reports",
    daily: lang === "vi" ? "Hàng ngày" : "Daily",
    latest: lang === "vi" ? "Mới nhất" : "Latest",
  };

  return (
    <Layout>
      <div className="dashboard-grid">
        <div className="dashboard-main">
          <section className="dashboard-section">
            <h2 className="section-title">{labels.latestIntel}</h2>
            <SignalHeatmap categories={sortedCategories} getCategoryMeta={(c) => getCategoryMeta(c, lang)} />
            <div className="category-stats-grid">
              {sortedCategories.map(([cat, items]) => {
                const meta = getCategoryMeta(cat, lang);
                const latest = items[0];
                const title = latest?.fields?.inferredTitle || latest?.frontmatter?.title || `${meta.displayLabel} — ${latest?.fields?.date || ""}`;
                return (
                  <a key={cat} href={langSlug(`/reports/${cat}/`, lang)} className="category-stat-card" style={{ borderLeftColor: meta.color }}>
                    <div className="stat-card-header">
                      <span className="stat-card-icon">{meta.icon}</span>
                      <span className="stat-card-label">{meta.displayLabel}</span>
                      <span className="stat-card-count">{items.length}</span>
                    </div>
                    <div className="stat-card-latest">
                      <span className="stat-card-date">{latest?.fields?.date || "—"}</span>
                      <span className="stat-card-title">{title.length > 80 ? title.substring(0, 80) + "…" : title}</span>
                    </div>
                  </a>
                );
              })}
            </div>
          </section>

          <section className="dashboard-section">
            <h2 className="section-title">{labels.dailyReports}</h2>
            <p className="section-subtitle">{labels.dailySub}</p>
            <div className="report-grid">
              {dailyReports.slice(0, 20).map((r) => {
                const meta = getCategoryMeta(r.fields?.category || "", lang);
                const title = r.frontmatter?.title || r.fields?.inferredTitle || `${meta.displayLabel} — ${r.fields?.date || ""}`;
                return <ReportCard key={r.id} slug={r.fields?.slug || ""} category={r.fields?.category || ""} date={r.fields?.date || ""} title={title} excerpt={r.excerpt || ""} icon={meta.icon} color={meta.color} lang={lang} />;
              })}
            </div>
          </section>

          {onDemandReports.length > 0 && (
            <section className="dashboard-section on-demand-section">
              <h2 className="section-title">{labels.onDemand}</h2>
              <p className="section-subtitle">{labels.onDemandSub}</p>
              <div className="report-grid">
                {onDemandReports.slice(0, 20).map((r) => {
                  const meta = getCategoryMeta(r.fields?.category || "", lang);
                  const title = r.frontmatter?.title || r.fields?.inferredTitle || `${meta.displayLabel} — ${r.fields?.date || ""}`;
                  return <ReportCard key={r.id} slug={r.fields?.slug || ""} category={r.fields?.category || ""} date={r.fields?.date || ""} title={title} excerpt={r.excerpt || ""} icon={meta.icon} color={meta.color} lang={lang} />;
                })}
              </div>
            </section>
          )}
        </div>

        <div className="dashboard-sidebar">
          <DataPanel title={labels.categories}>
            <ul className="category-list">
              {sortedCategories.map(([cat, items]) => {
                const meta = getCategoryMeta(cat, lang);
                return (
                  <li key={cat}>
                    <a href={langSlug(`/reports/${cat}/`, lang)} className="category-link">
                      <span className="cat-icon">{meta.icon}</span>
                      <span className="cat-label">{meta.displayLabel}</span>
                      <span className="cat-count">{items.length}</span>
                    </a>
                  </li>
                );
              })}
            </ul>
          </DataPanel>

          {onDemandReports.length > 0 && (
            <DataPanel title={labels.onDemandSide}>
              <ul className="category-list">
                {onDemandReports.slice(0, 10).map((report) => {
                  const meta = getCategoryMeta(report.fields?.category || "", lang);
                  const title = report.frontmatter?.title || report.fields?.inferredTitle || "Analysis";
                  return (
                    <li key={report.id}>
                      <a href={langSlug(report.fields?.slug || "/", lang)} className="category-link">
                        <span className="cat-icon">{meta.icon}</span>
                        <span className="cat-label" title={title}>{title.length > 35 ? title.substring(0, 35) + "…" : title}</span>
                      </a>
                    </li>
                  );
                })}
              </ul>
            </DataPanel>
          )}

          <DataPanel title={labels.stats}>
            <div className="stats-grid">
              <div className="stat-item">
                <span className="stat-value">{reports.length}</span>
                <span className="stat-label">{labels.total}</span>
              </div>
              <div className="stat-item">
                <span className="stat-value">{dailyReports.length}</span>
                <span className="stat-label">{labels.daily}</span>
              </div>
              <div className="stat-item">
                <span className="stat-value">{onDemandReports.length}</span>
                <span className="stat-label">On-Demand</span>
              </div>
              <div className="stat-item">
                <span className="stat-value">{dailyReports[0]?.fields?.date || "—"}</span>
                <span className="stat-label">{labels.latest}</span>
              </div>
            </div>
          </DataPanel>
        </div>
      </div>
    </Layout>
  );
};

export default IndexPage;

export const Head = ({ location }) => {
  const lang = location?.pathname?.startsWith("/en") ? "en" : "vi";
  return (
    <SEO
      title={lang === "vi" ? "Bobbie Intelligence — Terminal Tình báo" : "Bobbie Intelligence — Terminal"}
      description={lang === "vi"
        ? "Bảng điều khiển tình báo phong cách Bloomberg cho solo developer. Tín hiệu crypto, phân tích xu hướng, tình báo pháp lý."
        : "Bloomberg Terminal-style intelligence dashboard for solo developers. Crypto signals, trend analysis, legal intelligence, and opportunity radar."}
      path="/"
      lang={lang}
    />
  );
};

export const query = graphql`
  query IndexPage {
    allMarkdownRemark(sort: { fields: { date: DESC } }) {
      nodes {
        id
        fields {
          slug
          category
          categoryLabel
          categoryIcon
          date
          inferredTitle
          reportType
          lang
          baseName
        }
        frontmatter {
          title
          date
        }
        excerpt
      }
    }
  }
`;
